          to { opacity: 1; }
        }

        /* Mode 2 提示區直式注音 */
        .prompt-zhuyin-vertical {
          display: flex;
          justify-content: center;
          margin: 8px 0;
        }
        .prompt-zhuyin-vertical .vzy-xl {
          min-height: 80px;
        }

        /* 多音字橫排 */
        .multi-readings-row {
          display: flex;
          gap: 16px;
          justify-content: center;
          align-items: flex-start;
          flex-wrap: wrap;
        }
        .multi-reading {
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 4px;
        }
        .multi-reading .vzy { color: #1976d2; }
        .multi-pinyin {
          font-size: 0.8rem;
          color: #999;
        }

        /* ─── 闖關地圖 ─── */
        .dungeon-map-section {
          margin-top: 24px;
          padding: 20px;
          background: var(--card, #fff);
          border-radius: 18px;
          border: 2.5px solid var(--cloud, #e8e0d0);
          box-shadow: 0 4px 16px rgba(59,46,32,0.06);
        }
        .dungeon-title {
          display: flex;
          justify-content: space-between;
          align-items: center;
          font-size: 1.1rem;
          margin-bottom: 12px;
          color: var(--wood-dark, #5d4037);
        }
        .dungeon-progress-text {
          font-size: 0.9rem;
          color: #aaa;
          font-weight: 500;
        }
        .dungeon-progress-bar {
          width: 100%;
          height: 8px;
          background: var(--cloud, #e8e0d0);
          border-radius: 4px;
          margin-bottom: 20px;
          overflow: hidden;
        }
        .dungeon-progress-fill {
          height: 100%;
          background: linear-gradient(90deg, #ff9800, #ffc107, #ffeb3b);
          border-radius: 4px;
          transition: width 0.5s ease;
        }
        .dungeon-chest-grid {
          display: flex;
          flex-wrap: wrap;
          gap: 12px;
          justify-content: center;
        }
        .dungeon-chest {
          position: relative;
          width: 80px;
          text-align: center;
          padding: 12px 8px 8px;
          border-radius: 14px;
          cursor: pointer;
          transition: all 0.25s;
          border: 2.5px solid var(--cloud, #e8e0d0);
          background: var(--paper-warm, #faf6ed);
        }
        .dungeon-chest:hover {
          transform: translateY(-3px);
          box-shadow: 0 6px 16px rgba(59,46,32,0.1);
          border-color: #ff9800;
        }
        .dungeon-chest.cleared {
          border-color: #ff9800;
          background: linear-gradient(135deg, #fff8e1, #fff3cd);
        }
        .dungeon-chest.locked {
          opacity: 0.5;
        }
        .chest-icon { font-size: 2rem; line-height: 1; }
        .chest-label {
          font-size: 0.7rem;
          color: #aaa;
          margin-top: 4px;
          font-weight: 600;
        }
        .chest-emoji { font-size: 1.1rem; margin-top: 2px; }
        .chest-check {
          position: absolute;
          top: -4px;
          right: -4px;
          width: 20px;
          height: 20px;
          background: #4caf50;
          color: white;
          border-radius: 50%;
          font-size: 0.65rem;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: bold;
        }
        .chest-connector {
          position: absolute;
          right: -14px;
          top: 50%;
          width: 14px;
          height: 2px;
          background: var(--cloud, #e8e0d0);
        }
        .chest-connector.active {
          background: #ff9800;
        }

        /* ─── 通關 Banner ─── */
        .dungeon-clear-banner {
          margin: 16px 0;
          padding: 14px 20px;
          background: linear-gradient(135deg, #fff8e1, #fff3cd);
          border: 2.5px solid #ff9800;
          border-radius: 14px;
          text-align: center;
          font-size: 1rem;
          font-weight: 700;
          color: #e65100;
          animation: clearBounce 0.5s ease;
        }
        @keyframes clearBounce {
          0% { transform: scale(0.9); opacity: 0; }
          60% { transform: scale(1.05); }
          100% { transform: scale(1); opacity: 1; }
        }

        /* ─── 造字工坊按鈕 ─── */
        .forge-btn {
          display: flex;
