          border: 2.5px solid #ffcc02 !important;
        }
        .forge-radical-display {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 12px;
          margin: 20px 0 16px;
          flex-wrap: wrap;
        }
        .forge-radical-char {
          font-size: 3.5rem;
          font-weight: 900;
          color: #e65100;
          line-height: 1;
        }
        .forge-plus, .forge-equals {
          font-size: 2rem;
          color: #bbb;
          font-weight: 300;
        }
        .forge-mystery {
          font-size: 3.5rem;
          color: #ff9800;
          font-weight: 900;
          line-height: 1;
          animation: mysteryPulse 1.5s infinite;
        }
        @keyframes mysteryPulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.35; }
        }
        .forge-result-char {
          font-size: 3.5rem;
          font-weight: 900;
          color: #2e7d32;
          line-height: 1;
