    setQuizPool(pool);
    setCurrentIdx(0);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setScore(0);
    setStreak(0);
    setBestStreak(0);
    setTotal(0);
    setShowResult(false);
    setIsPaused(false);
    setEarlyEnd(false);
    setEarlyEndTime(null);
    setTimeLeft(timerValue);
    setAnimKey(0);
    setQuestionStartTime(Date.now());
    setQuestionTimes([]);
    setScreen("quiz");
  }, [timerValue]);

  const handleStartNormal = () => {
