  const handleStartFromRadical = () => {
    const chars = filterChars(level, selectedRadicals);
    if (chars.length === 0) return;
    quizLevelRef.current = level;
    const pool = generateQuizPool(chars, Math.min(chars.length, 999));
    startQuiz(pool);
  };

  // ─── 闖關地圖：關卡定義 ──────────────────────────────────────────
  const DUNGEON_STAGES = LEVELS.map(lv => ({
    id: lv.id,
    emoji: lv.emoji,
    cleared: !!clearedLevels[lv.id],
  }));

  // eslint-disable-next-line no-unused-vars
  const dungeonProgress = DUNGEON_STAGES.filter(s => s.cleared).length;
  // eslint-disable-next-line no-unused-vars
  const dungeonTotal = DUNGEON_STAGES.length;

  const markLevelCleared = (lvId) => {
    setClearedLevels(prev => {
      const next = { ...prev, [lvId]: true };
      localStorage.setItem("hanziDungeonCleared", JSON.stringify(next));
      return next;
    });
  };

  // ─── 造字工坊：部首＋邊旁組合 ──────────────────────────────────
  // 拆字資料：radical → [{ component, result }]
  const RADICAL_COMBINE_DATA = [
    { radical: "艹", pairs: [{ component: "早", result: "草" }, { component: "化", result: "花" }, { component: "古", result: "苦" }, { component: "明", result: "萌" }, { component: "各", result: "落" }, { component: "每", result: "莓" }, { component: "包", result: "苞" }, { component: "加", result: "茄" }, { component: "何", result: "荷" }, { component: "夢", result: "蒙" }] },
    { radical: "氵", pairs: [{ component: "每", result: "海" }, { component: "可", result: "河" }, { component: "胡", result: "湖" }, { component: "青", result: "清" }, { component: "吉", result: "潔" }, { component: "皮", result: "波" }, { component: "主", result: "注" }, { component: "白", result: "泊" }, { component: "少", result: "沙" }, { component: "令", result: "泠" }] },
    { radical: "木", pairs: [{ component: "目", result: "相" }, { component: "才", result: "材" }, { component: "交", result: "校" }, { component: "風", result: "楓" }, { component: "東", result: "棟" }, { component: "反", result: "板" }, { component: "寸", result: "村" }, { component: "果", result: "棵" }, { component: "昆", result: "棍" }, { component: "喬", result: "橋" }] },
    { radical: "火", pairs: [{ component: "山", result: "災" }, { component: "者", result: "煮" }, { component: "然", result: "燃" }, { component: "登", result: "燈" }, { component: "因", result: "煙" }, { component: "尞", result: "燎" }, { component: "堯", result: "燒" }, { component: "少", result: "炒" }] },
    { radical: "亻", pairs: [{ component: "立", result: "位" }, { component: "建", result: "健" }, { component: "尤", result: "優" }, { component: "象", result: "像" }, { component: "更", result: "便" }, { component: "半", result: "伴" }, { component: "寺", result: "侍" }, { component: "至", result: "侄" }, { component: "白", result: "伯" }, { component: "主", result: "住" }] },
    { radical: "口", pairs: [{ component: "大", result: "吞" }, { component: "乞", result: "吃" }, { component: "合", result: "哈" }, { component: "甘", result: "甜" }, { component: "欠", result: "吹" }, { component: "巴", result: "吧" }, { component: "令", result: "命" }, { component: "各", result: "咯" }] },
    { radical: "言", pairs: [{ component: "果", result: "課" }, { component: "寺", result: "詩" }, { component: "式", result: "試" }, { component: "五", result: "語" }, { component: "兌", result: "說" }, { component: "周", result: "調" }, { component: "侖", result: "論" }, { component: "青", result: "請" }] },
    { radical: "心", pairs: [{ component: "相", result: "想" }, { component: "咸", result: "感" }, { component: "亡", result: "忙" }, { component: "生", result: "性" }, { component: "田", result: "思" }, { component: "旦", result: "悶" }, { component: "青", result: "情" }, { component: "吳", result: "悟" }] },
    { radical: "扌", pairs: [{ component: "口", result: "扣" }, { component: "丁", result: "打" }, { component: "旨", result: "指" }, { component: "巴", result: "把" }, { component: "奐", result: "換" }, { component: "般", result: "搬" }, { component: "軍", result: "揮" }, { component: "是", result: "提" }] },
    { radical: "土", pairs: [{ component: "也", result: "地" }, { component: "寺", result: "堅" }, { component: "曾", result: "增" }, { component: "甬", result: "塘" }, { component: "里", result: "埋" }, { component: "皮", result: "坡" }, { component: "旦", result: "坦" }] },
  ];

  const startForge = () => {
    const allPairs = [];
    RADICAL_COMBINE_DATA.forEach(group => {
      group.pairs.forEach(pair => {
        allPairs.push({ radical: group.radical, ...pair });
      });
    });
    const shuffled = allPairs.sort(() => Math.random() - 0.5).slice(0, 15);
    setForgePool(shuffled);
    setForgeIdx(0);
    setForgeScore(0);
    setForgeTotal(0);
    setForgeSelected(null);
    setForgeWrongs(new Set());
    setForgeResult(false);
    setForgeAnimKey(0);
    setForgeHistory([]);
    generateForgeQuestion(shuffled, 0);
    setScreen("forge");
  };

  const generateForgeQuestion = (pool, idx) => {
    if (idx >= pool.length) {
      setForgeResult(true);
      return;
    }
    const item = pool[idx];
    // 找出當前部首的所有合法 component，確保錯誤選項不在其中
    const currentRadicalGroup = RADICAL_COMBINE_DATA.find(g => g.radical === item.radical);
    const validComponentsForRadical = new Set(
      currentRadicalGroup ? currentRadicalGroup.pairs.map(p => p.component) : []
    );
    // Pick 2 wrong components from OTHER radicals, excluding any valid component for this radical
    const wrongComponents = RADICAL_COMBINE_DATA
      .flatMap(g => g.pairs.map(p => p.component))
      .filter(c => !validComponentsForRadical.has(c))
      .sort(() => Math.random() - 0.5)
      .slice(0, 2);
    const opts = [item.component, ...wrongComponents].sort(() => Math.random() - 0.5);
    setForgeQuestion({ radical: item.radical, answer: item.component, result: item.result, options: opts });
    setForgeAnimKey(k => k + 1);
  };

  const handleForgeSelect = (opt) => {
    if (forgeSelected) return;
    if (forgeWrongs.has(opt)) return;
    const isCorrect = opt === forgeQuestion.answer;
    if (isCorrect) {
      setForgeSelected(opt);
      setForgeScore(s => s + 1);
      setForgeTotal(t => t + 1);
      // 紀錄到歷史
      setForgeHistory(prev => [...prev, {
        radical: forgeQuestion.radical,
        component: forgeQuestion.answer,
        result: forgeQuestion.result,
        zhuyin: CHAR_ZHUYIN_MAP[forgeQuestion.result] || '',
      }]);
      setTimeout(() => {
        const next = forgeIdx + 1;
        setForgeIdx(next);
        setForgeSelected(null);
        setForgeWrongs(new Set());
        generateForgeQuestion(forgePool, next);
      }, 1200);
    } else {
      setForgeWrongs(prev => new Set([...prev, opt]));
      if (forgeWrongs.size === 0) {
        // first wrong
        setForgeTotal(t => t + 1);
      }
    }
  };

  const handleImport = () => {
    const parsed = parseMarkdownImport(importText);
    if (parsed.length === 0) return;
    setImportText("");
    quizLevelRef.current = 5;
    startQuiz(parsed);
  };

  // ─── 變聲秘術：從全字庫取得多音字 ──────────────────────────────
  const POLY_CHARS = ALL_CHARS.filter(c => c.readings && c.readings.length > 1 && c.words && c.words.length >= 2);

  // 將每個多音字的 words 依 readings 數量均分，建立 reading→word 對應
  const buildPolyPool = () => {
    const allItems = [];
    POLY_CHARS.forEach(charData => {
      const rCount = charData.readings.length;
      const wCount = charData.words.length;
      const perReading = Math.max(1, Math.floor(wCount / rCount));

      const readingWordMap = charData.readings.map((r, i) => {
        const start = i * perReading;
        const end = i === rCount - 1 ? wCount : start + perReading;
        return { zhuyin: r.zhuyin, pinyin: r.pinyin, words: charData.words.slice(start, end) };
      });

      readingWordMap.forEach(rwm => {
        if (rwm.words.length === 0) return;
        allItems.push({
          char: charData.char,
          zhuyin: rwm.zhuyin,
          word: rwm.words[0],
          sentence: rwm.words.length > 1 ? rwm.words[1] : rwm.words[0],
          allReadings: readingWordMap.map(r => ({ zhuyin: r.zhuyin, word: r.words[0] || '' })),
        });
      });
    });
    return allItems;
  };

  // eslint-disable-next-line no-unused-vars
  const polyTotalCount = POLY_CHARS.length;

  const startPolyphone = () => {
    const allItems = buildPolyPool();
    const shuffled = allItems.sort(() => Math.random() - 0.5);
    setPolyPool(shuffled);
    setPolyIdx(0);
    setPolyScore(0);
    setPolyTotal(0);
    setPolySelected(null);
    setPolyWrongs(new Set());
    setPolyResult(false);
    setPolyAnimKey(0);
    setPolyHistory([]);
    generatePolyQuestion(shuffled, 0, allItems);
    setScreen("polyphone");
  };

  const generatePolyQuestion = (pool, idx, allItems) => {
    if (idx >= pool.length) {
      setPolyResult(true);
      return;
    }
    const item = pool[idx];
    const sameCharWrong = item.allReadings
      .filter(r => r.word && r.word !== item.word)
      .map(r => r.word);
    const src = allItems || pool;
    const otherWords = src
      .filter(p => p.char !== item.char && p.word)
      .map(p => p.word)
      .sort(() => Math.random() - 0.5);
    const finalWrongs = [...new Set([...sameCharWrong.slice(0, 1), ...otherWords])]
      .filter(w => w !== item.word)
      .slice(0, 2);
    const opts = [item.word, ...finalWrongs].sort(() => Math.random() - 0.5);
    setPolyQuestion({
      char: item.char,
      zhuyin: item.zhuyin,
      answer: item.word,
      sentence: item.sentence,
      allReadings: item.allReadings,
      options: opts,
    });
    setPolyAnimKey(k => k + 1);
  };

  const handlePolySelect = (opt) => {
    if (polySelected) return;
    if (polyWrongs.has(opt)) return;
    const isCorrect = opt === polyQuestion.answer;
    if (isCorrect) {
      setPolySelected(opt);
      setPolyScore(s => s + 1);
      setPolyTotal(t => t + 1);
      setPolyHistory(prev => [...prev, {
        char: polyQuestion.char,
        zhuyin: polyQuestion.zhuyin,
        word: polyQuestion.answer,
      }]);
      setTimeout(() => {
        const next = polyIdx + 1;
        setPolyIdx(next);
        setPolySelected(null);
        setPolyWrongs(new Set());
        generatePolyQuestion(polyPool, next);
      }, 1200);
    } else {
      setPolyWrongs(prev => new Set([...prev, opt]));
      if (polyWrongs.size === 0) {
        setPolyTotal(t => t + 1);
      }
    }
  };

  // ─── 下一題 ────────────────────────────────────────────────────
  const goNext = useCallback(() => {
    const elapsed = Date.now() - (questionStartTime || Date.now());
    setQuestionTimes(prev => [...prev, {
      char: quizPool[currentIdx]?.char,
      zhuyin: quizPool[currentIdx]?.zhuyin,
      time: elapsed,
      correct: firstAttemptCorrect,
    }]);

    const next = currentIdx + 1;
    if (next >= quizPool.length) {
      setShowResult(true);
      return;
    }
    setCurrentIdx(next);
    const q = generateQuestion(quizPool[next], quizPool, quizLevelRef.current);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setAnimKey(k => k + 1);
    setQuestionStartTime(Date.now());
  }, [currentIdx, quizPool, questionStartTime, firstAttemptCorrect]);

  // ─── 選擇答案（嚴格模式）──────────────────────────────────────
  const handleSelect = (opt) => {
    if (!question) return;
    // 已經選對了就不能再點
    if (selected === question.answer) return;
    // 已經點過的錯誤選項不能再點
    if (wrongSelections.has(opt)) return;

    const isCorrect = opt === question.answer;

    if (isCorrect) {
      setSelected(opt);
      // 只有第一次就選對才計分
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(true);
        setScore(s => s + 1);
        setStreak(s => {
          const ns = s + 1;
          setBestStreak(b => Math.max(b, ns));
          return ns;
        });
      }
      setTotal(t => t + 1);
      // 自動跳下一題
      setTimeout(goNext, 800);
    } else {
      // 錯誤：標記此選項，不顯示正確答案
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(false);
        setStreak(0);
        setTotal(t => t + 1);
      }
      setWrongSelections(prev => new Set([...prev, opt]));
    }
  };

  // ─── 暫停/結束 ────────────────────────────────────────────────
  const togglePause = () => setIsPaused(p => !p);
  const endGame = (isEarly = false) => {
    clearInterval(timerRef.current);
    if (isEarly) {
      setEarlyEnd(true);
      setEarlyEndTime(formatTime(timeLeft));
    }
    // Record last question time
    if (quizPool[currentIdx] && questionStartTime) {
      const elapsed = Date.now() - questionStartTime;
      setQuestionTimes(prev => [...prev, {
        char: quizPool[currentIdx].char,
        zhuyin: quizPool[currentIdx].zhuyin,
        time: elapsed,
        correct: firstAttemptCorrect,
      }]);
    }
    setShowResult(true);
    setIsPaused(false);
  };

  // ─── 部首操作 ──────────────────────────────────────────────────
  const toggleRadical = (r) => {
    setSelectedRadicals(prev => {
      const next = new Set(prev);
      if (next.has(r)) next.delete(r); else next.add(r);
      return next;
    });
  };
  const selectAllRadicals = () => setSelectedRadicals(new Set(ALL_RADICALS));
  const clearAllRadicals = () => setSelectedRadicals(new Set());

  // ─── 弱點分析：思考時間最久前 5 字 ─────────────────────────────
  const weaknesses = [...questionTimes]
    .sort((a, b) => b.time - a.time)
    .slice(0, 5);

  // ─── 當前題目的多音字提示 ──────────────────────────────────────
  const currentItem = quizPool[currentIdx];
  const multiReadings = currentItem?.readings;

  // ═══════════════════════════════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════════════════════════════
  return (
    <div className="app">
      <style>{`
        /* ─── 首頁次要按鈕群組 ─── */
        .secondary-btns {
          display: flex;
          gap: 10px;
          margin-top: 12px;
          margin-bottom: 16px;
        }
