          background: var(--card, #fff);
          font-family: inherit;
          cursor: pointer;
          transition: all 0.25s;
        }
        .secondary-game-btn:hover {
          transform: translateY(-2px);
          box-shadow: 0 4px 12px rgba(59,46,32,0.1);
        }
        .secondary-game-btn:active {
          transform: scale(0.97);
        }
        .sg-icon {
          font-size: 1.8rem;
          line-height: 1;
        }
        .sg-label {
          font-size: 0.82rem;
          font-weight: 700;
          color: var(--ink, #3b2e20);
          letter-spacing: 1px;
        }
        .forge-mini { border-color: #ffcc80; background: linear-gradient(135deg, #fff8e8, #fff3d6); }
        .forge-mini:hover { border-color: #ff9800; }
        .forge-mini .sg-label { color: #e65100; }
        .poly-mini { border-color: #ce93d8; background: linear-gradient(135deg, #fce4ec, #f3e5f5); }
        .poly-mini:hover { border-color: #ab47bc; }
        .poly-mini .sg-label { color: #7b1fa2; }
        .import-mini { border-color: #a5d6a7; background: linear-gradient(135deg, #e8f5e9, #f1f8e9); }
        .import-mini:hover { border-color: #4caf50; }
        .import-mini .sg-label { color: #2e7d32; }

        @media (max-width: 420px) {
          .secondary-btns { gap: 8px; }
          .secondary-game-btn { padding: 12px 6px; border-radius: 14px; }
          .sg-icon { font-size: 1.5rem; }
          .sg-label { font-size: 0.72rem; }
        }

        /* ─── 直式注音 ─── */
        .vzy {
          display: inline-flex;
          flex-direction: row;
