      {screen === "quiz" && !showResult && question && currentItem && (
        <>
          {/* 暫停遮罩 */}
          {isPaused && (
            <div className="pause-overlay">
              <div className="pause-icon">🏕️</div>
              <h2>{t.pauseTitle}</h2>
              <button className="btn-primary" onClick={togglePause}>{t.pauseResume}</button>
              <button className="btn-secondary" onClick={() => endGame(true)}>{t.pauseEnd}</button>
            </div>
          )}

          <div className="header" style={{ position: "relative" }}>
            <h1>
              {question.mode === 1 ? t.quizTitleMode1 :
                question.mode === 2 ? t.quizTitleMode2 : t.quizTitleMode3}
            </h1>
          </div>

          <div className="quiz-top">
            <span className="quiz-progress">
              {t.quizProgress.replace("{{current}}", currentIdx + 1).replace("{{total}}", quizPool.length)}
            </span>
            <div className="quiz-score-bar">
              {streak >= 2 && (
                <span className="streak-badge" key={streak}>{t.streak.replace("{{streak}}", streak)}</span>
              )}
              <span>✓ {score}</span>
              {timerValue > 0 && (
                <span className={`quiz-timer ${timeLeft <= 10 ? "warning" : ""}`}>
                  ⏱ {formatTime(timeLeft)}
                </span>
              )}
            </div>
          </div>

          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${(currentIdx / quizPool.length) * 100}%` }} />
          </div>

          <div className="quiz-card" key={animKey}>
            {question.mode === 1 && (
              <>
                <div className="prompt-label">{t.promptMode1}</div>
                <div className="prompt-char">{currentItem.char}</div>
                <div className="prompt-pinyin-hint">{currentItem.pinyin}</div>
              </>
            )}
            {question.mode === 2 && (
              <>
                <div className="prompt-label">{t.promptMode2}</div>
                <div className="prompt-zhuyin-vertical">
                  <VerticalZhuyin zhuyin={currentItem.zhuyin} size="xl" />
                </div>
                <div className="prompt-pinyin-hint">{currentItem.pinyin}</div>
              </>
            )}
            {question.mode === 3 && (
              <>
                <div className="prompt-label">{t.promptMode3}</div>
                <div className="prompt-word-zy">
                  {[...question.wordBlank].map((ch, i) => (
                    ch === '＿'
                      ? <span key={i} className="pw-blank">＿</span>
                      : <span key={i} className="pw-char-group">
                          <span className="pw-char">{ch}</span>
                          {CHAR_ZHUYIN_MAP[ch] && <VerticalZhuyin zhuyin={CHAR_ZHUYIN_MAP[ch]} size="sm" />}
                        </span>
                  ))}
                </div>
              </>
            )}

            {/* 多音字提示 */}
            {multiReadings && multiReadings.length > 1 && (
              <div className="multi-hint">
                <div className="multi-title">{t.multiHint}</div>
                <div className="multi-readings-row">
                  {multiReadings
                    .filter(r => r.zhuyin !== currentItem.zhuyin)
                    .map((r, i) => (
                      <div key={i} className="multi-reading">
                        <VerticalZhuyin zhuyin={r.zhuyin} size="sm" />
                        <span className="multi-pinyin">{r.pinyin}</span>
                      </div>
                    ))}
                </div>
              </div>
            )}
          </div>

          <div className="options-grid">
            {question.options.map((opt, i) => {
              let cls = "option-btn";
              const answered = selected === question.answer;
              if (answered) {
                cls += " disabled";
                if (opt === question.answer) cls += " correct-opt";
                else if (wrongSelections.has(opt)) cls += " wrong-opt";
                else cls += " greyed";
              } else {
                if (wrongSelections.has(opt)) cls += " wrong-opt disabled";
              }
              return (
                <button key={i} className={cls} onClick={() => handleSelect(opt)}>
                  {question.mode === 1
                    ? <VerticalZhuyin zhuyin={opt} size="lg" />
                    : <>
                        <span className="opt-char-only">{opt}</span>
                        {answered && <VerticalZhuyin zhuyin={CHAR_ZHUYIN_MAP[opt]} size="sm" />}
                      </>
                  }
                </button>
              );
            })}
          </div>

          <div className="quiz-controls">
            <button className="ctrl-btn" onClick={togglePause}>{t.camp}</button>
          </div>
        </>
      )}

      {/* ═══ RESULT ═══ */}
      {screen === "quiz" && showResult && (
        <>
          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => setScreen("home")}>←</button>
            <h1>{t.resultTitle}</h1>
          </div>

          <div className="result-card">
            {(() => {
              const accuracyPercent = total > 0 ? Math.round((score / total) * 100) : 0;
              const rank = t.resultRanks.find(r => accuracyPercent >= r.min) || t.resultRanks[t.resultRanks.length - 1];
              return (
                <>
                  <div className="result-emoji">{rank.emoji}</div>
                  <h2>{rank.text}</h2>
                </>
              );
            })()}
            <div className="result-score">{score} / {total}</div>
            <div className="result-detail">
              {t.accuracy.replace("{{percent}}", total > 0 ? Math.round((score / total) * 100) : 0)}
              {bestStreak >= 2 && <>{t.bestStreak.replace("{{streak}}", bestStreak)}</>}
              {earlyEnd && earlyEndTime && (
                <><br />{t.earlyEnd.replace("{{time}}", earlyEndTime)}</>
              )}
            </div>
            {/* 通關判定 */}
            {total > 0 && Math.round((score / total) * 100) >= 80 && (
              <div className="dungeon-clear-banner">
                🏰 {lang === "zh"
                  ? `Lv.${quizLevelRef.current} 關卡通過！寶箱已開啟！`
                  : `Lv.${quizLevelRef.current} Stage Cleared! Chest Unlocked!`}
              </div>
            )}
            <div className="result-actions">
              <button className="btn-primary" onClick={() => {
                handleStartNormal();
              }}>{t.retry}</button>
              <button className="btn-secondary" onClick={() => setScreen("home")}>{t.home}</button>
            </div>
          </div>

          {/* 弱點分析 */}
          {weaknesses.length > 0 && (
            <div className="weakness-section">
              <h4>{t.weaknessTitle}</h4>
              {weaknesses.map((w, i) => (
                <div key={i} className="weakness-item">
                  <div className="weakness-char">{w.char}</div>
                  <div className="weakness-info">
                    {w.zhuyin}
                    {w.correct === false && ` · ${t.miss}`}
                    {w.correct === true && ` · ${t.hit}`}
                  </div>
                  <div className="weakness-time">
                    {(w.time / 1000).toFixed(1)}s
                  </div>
                </div>
              ))}
            </div>
          )}
        </>
      )}

      {/* ═══ FORGE 造字工坊 ═══ */}
      {screen === "forge" && !forgeResult && forgeQuestion && (
        <>
          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => setScreen("home")}>←</button>
            <h1>{lang === "zh" ? "🔨 造字工坊" : "🔨 Forge"}</h1>
          </div>

          <div className="quiz-top">
            <span className="quiz-progress">
              {lang === "zh" ? `第 ${forgeIdx + 1} / ${forgePool.length} 題` : `${forgeIdx + 1} / ${forgePool.length}`}
            </span>
            <span>✓ {forgeScore}</span>
          </div>

          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${(forgeIdx / forgePool.length) * 100}%` }} />
          </div>

          <div className="quiz-card forge-card" key={forgeAnimKey}>
            <div className="prompt-label">{lang === "zh" ? "哪個邊旁可以和部首組成漢字？" : "Which component combines with this radical?"}</div>
            <div className="forge-radical-display">
              <span className="forge-radical-char">{forgeQuestion.radical}</span>
              <span className="forge-plus">＋</span>
              <span className="forge-mystery">？</span>
              <span className="forge-equals">＝</span>
              <span className="forge-result-char">{forgeSelected ? forgeQuestion.result : "？"}</span>
            </div>
            {forgeSelected && (
              <div className="forge-reveal">
                <span className="forge-reveal-text">
                  {forgeQuestion.radical} ＋ {forgeQuestion.answer} ＝ <strong>{forgeQuestion.result}</strong>
                </span>
                <div className="forge-reveal-zy">
                  <VerticalZhuyin zhuyin={CHAR_ZHUYIN_MAP[forgeQuestion.result]} size="lg" />
                </div>
              </div>
            )}
          </div>

          <div className="options-grid">
            {forgeQuestion.options.map((opt, i) => {
              let cls = "option-btn";
              if (forgeSelected) {
                cls += " disabled";
                if (opt === forgeQuestion.answer) cls += " correct-opt";
                else if (forgeWrongs.has(opt)) cls += " wrong-opt";
                else cls += " greyed";
              } else {
                if (forgeWrongs.has(opt)) cls += " wrong-opt disabled";
              }
              return (
                <button key={i} className={cls} onClick={() => handleForgeSelect(opt)}>
                  <CharWithZhuyin char={opt} size="md" />
                </button>
              );
            })}
          </div>

          {/* 造字歷史紀錄 */}
          {forgeHistory.length > 0 && (
            <div className="forge-history">
              <h4 className="forge-history-title">{lang === "zh" ? "🔥 鍛造紀錄" : "🔥 Forge Log"}</h4>
              <div className="forge-history-list">
                {forgeHistory.map((h, i) => (
                  <div key={i} className="forge-history-item">
                    <span className="fh-formula">{h.radical}＋{h.component}</span>
                    <span className="fh-eq">＝</span>
                    <span className="fh-result">{h.result}</span>
                    <VerticalZhuyin zhuyin={h.zhuyin} size="sm" />
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      )}

      {/* ═══ FORGE RESULT ═══ */}
      {screen === "forge" && forgeResult && (
        <>
          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => setScreen("home")}>←</button>
            <h1>{lang === "zh" ? "工坊成果" : "Forge Results"}</h1>
          </div>
          <div className="result-card">
            <div className="result-emoji">{forgeTotal > 0 && (forgeScore / forgeTotal) >= 0.8 ? "⚒️" : "🔨"}</div>
            <h2>{forgeTotal > 0 && (forgeScore / forgeTotal) >= 0.8
              ? (lang === "zh" ? "鑄字大師！" : "Master Forger!")
              : (lang === "zh" ? "繼續鍛造吧！" : "Keep forging!")}</h2>
            <div className="result-score">{forgeScore} / {forgeTotal}</div>
            <div className="result-detail">
              {lang === "zh" ? "正確率" : "Accuracy"} {forgeTotal > 0 ? Math.round((forgeScore / forgeTotal) * 100) : 0}%
            </div>
            <div className="result-actions">
              <button className="btn-primary" onClick={startForge}>{lang === "zh" ? "再鍛一次" : "Forge Again"}</button>
              <button className="btn-secondary" onClick={() => setScreen("home")}>{t.home}</button>
            </div>
          </div>

          {/* 完整鍛造紀錄 */}
          {forgeHistory.length > 0 && (
            <div className="forge-history forge-history-final">
              <h4 className="forge-history-title">{lang === "zh" ? "📜 本次鍛造全紀錄" : "📜 Full Forge Log"}</h4>
              <div className="forge-history-list">
                {forgeHistory.map((h, i) => (
                  <div key={i} className="forge-history-item">
                    <span className="fh-formula">{h.radical}＋{h.component}</span>
                    <span className="fh-eq">＝</span>
                    <span className="fh-result">{h.result}</span>
                    <VerticalZhuyin zhuyin={h.zhuyin} size="sm" />
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      )}

      {/* ═══ POLYPHONE 變聲秘術 — 答題中 ═══ */}
      {screen === "polyphone" && !polyResult && polyQuestion && (
        <>
          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => setScreen("home")}>←</button>
            <h1>{lang === "zh" ? "🔮 變聲秘術" : "🔮 Voice-Shift Arcana"}</h1>
          </div>

          <div className="quiz-top">
            <span className="quiz-progress">
              {lang === "zh" ? `第 ${polyIdx + 1} / ${polyPool.length} 題` : `${polyIdx + 1} / ${polyPool.length}`}
            </span>
            <span style={{ color: 'var(--jade)' }}>✓ {polyScore}</span>
          </div>

          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${(polyIdx / polyPool.length) * 100}%`, background: 'linear-gradient(90deg, #6c3483, #9b59b6, #c39bd3)' }} />
          </div>

          <div className="quiz-card poly-quiz-card" key={polyAnimKey}>
            <div className="prompt-label">{lang === "zh" ? "此字讀這個音時，正確的造詞是？" : "Which word uses this reading?"}</div>
            <div className="poly-char-display">{polyQuestion.char}</div>
            <div className="poly-zhuyin-display">
              <VerticalZhuyin zhuyin={polyQuestion.zhuyin} size="lg" />
            </div>
            <div className="poly-sentence-hint">
              {lang === "zh" ? "提示：" : "Hint: "}{polyQuestion.sentence}
            </div>
            {polySelected && (
              <div className="poly-reveal-readings">
                <div className="poly-reveal-title">{lang === "zh" ? "📖 此字的所有讀音" : "📖 All readings"}</div>
                <div className="poly-reveal-list">
                  {polyQuestion.allReadings.map((r, i) => (
                    <span key={i} className="poly-reveal-item">
                      <VerticalZhuyin zhuyin={r.zhuyin} size="sm" />
                      <span className="poly-reveal-word">{r.word}</span>
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>

          <div className="options-grid">
            {polyQuestion.options.map((opt, i) => {
              let cls = "option-btn poly-option";
              if (polySelected) {
                cls += " disabled";
                if (opt === polyQuestion.answer) cls += " correct-opt";
                else if (polyWrongs.has(opt)) cls += " wrong-opt";
                else cls += " greyed";
              } else {
                if (polyWrongs.has(opt)) cls += " wrong-opt disabled";
              }
              return (
                <button key={i} className={cls} onClick={() => handlePolySelect(opt)}>
                  <span className="poly-opt-word">{opt}</span>
                </button>
              );
            })}
          </div>

          {/* 修煉紀錄 */}
          {polyHistory.length > 0 && (
            <div className="poly-history">
              <h4 className="poly-history-title">{lang === "zh" ? "🔮 修煉紀錄" : "🔮 Training Log"}</h4>
              <div className="poly-history-list">
                {polyHistory.map((h, i) => (
                  <div key={i} className="poly-history-item">
                    <span className="ph-char">{h.char}</span>
                    <VerticalZhuyin zhuyin={h.zhuyin} size="sm" />
                    <span className="ph-arrow">→</span>
                    <span className="ph-word">{h.word}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      )}

      {/* ═══ POLYPHONE RESULT 變聲秘術結果 ═══ */}
      {screen === "polyphone" && polyResult && (
        <>
          <div className="header" style={{ position: "relative" }}>
            <button className="back-btn" onClick={() => setScreen("home")}>←</button>
            <h1>{lang === "zh" ? "修煉成果" : "Training Results"}</h1>
          </div>
          <div className="result-card">
            <div className="result-emoji">{polyTotal > 0 && (polyScore / polyTotal) >= 0.8 ? "🔮" : "✨"}</div>
            <h2>{polyTotal > 0 && (polyScore / polyTotal) >= 0.8
              ? (lang === "zh" ? "變聲大師！" : "Voice-Shift Master!")
              : (lang === "zh" ? "繼續修煉吧！" : "Keep training!")}</h2>
            <div className="result-score">{polyScore} / {polyTotal}</div>
            <div className="result-detail">
              {lang === "zh" ? "正確率" : "Accuracy"} {polyTotal > 0 ? Math.round((polyScore / polyTotal) * 100) : 0}%
            </div>
            <div className="result-actions">
              <button className="btn-primary" onClick={startPolyphone}>{lang === "zh" ? "再修煉一次" : "Train Again"}</button>
              <button className="btn-secondary" onClick={() => setScreen("home")}>{t.home}</button>
            </div>
          </div>

          {/* 完整修煉紀錄 */}
          {polyHistory.length > 0 && (
            <div className="poly-history poly-history-final">
              <h4 className="poly-history-title">{lang === "zh" ? "📜 本次修煉全紀錄" : "📜 Full Training Log"}</h4>
              <div className="poly-history-list">
                {polyHistory.map((h, i) => (
                  <div key={i} className="poly-history-item">
                    <span className="ph-char">{h.char}</span>
                    <VerticalZhuyin zhuyin={h.zhuyin} size="sm" />
                    <span className="ph-arrow">→</span>
                    <span className="ph-word">{h.word}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}
